const body = $json.body ?? $json;

const toNullableNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
};

const glucoseRaw = toNullableNumber(body.glucose);
const glucoseMmol = glucoseRaw === null ? null : Number((glucoseRaw / 18).toFixed(1));

const payload = {
  heart_rate: toNullableNumber(body.heart_rate),
  glucose_raw: glucoseRaw,
  glucose_mmol: glucoseMmol,
  weight: toNullableNumber(body.weight),
  sleep_hours: toNullableNumber(body.sleep_hours),
  timestamp: typeof body.timestamp === 'string' && body.timestamp.trim()
    ? body.timestamp.trim()
    : new Date().toISOString(),
};

return [{
  json: {
    payload,
    received_at: new Date().toISOString(),
    source_ip: $json.headers?.['x-forwarded-for'] || $json.headers?.['x-real-ip'] || '',
  },
}];

const payload = $json.payload || {};
const alerts = [];

if (payload.heart_rate !== null && payload.heart_rate > 85) {
  alerts.push(`High heart rate: ${payload.heart_rate} bpm`);
}

if (payload.glucose_mmol !== null && payload.glucose_mmol > 6.0) {
  alerts.push(`High glucose: ${payload.glucose_mmol} mmol/L`);
}

if (payload.sleep_hours !== null && payload.sleep_hours < 6) {
  alerts.push(`Low sleep: ${payload.sleep_hours} hours in the last 24h`);
}

const lines = [
  'HEALTH AGENT ALERT',
  `Timestamp: ${payload.timestamp}`,
  '',
  `heart_rate: ${payload.heart_rate ?? 'null'}`,
  `glucose_mmol: ${payload.glucose_mmol ?? 'null'}`,
  `weight: ${payload.weight ?? 'null'}`,
  `sleep_hours: ${payload.sleep_hours ?? 'null'}`,
  '',
  alerts.length ? 'Alerts:' : 'No alerts triggered.',
];

for (const alert of alerts) lines.push(`- ${alert}`);

const hasTelegram = !!($env.TELEGRAM_BOT_TOKEN && $env.TELEGRAM_CHAT_ID);
const sendTelegram = alerts.length > 0 && hasTelegram ? 1 : 0;

return [{
  json: {
    payload,
    received_at: $json.received_at,
    source_ip: $json.source_ip,
    alerts,
    alert_count: alerts.length,
    telegram_enabled: hasTelegram,
    send_telegram: sendTelegram,
    telegram_text: lines.join('\n'),
  },
}];

return [{
  json: {
    ok: true,
    telegram_sent: true,
    alerts: $json.alerts,
    alert_count: $json.alert_count,
    payload: $json.payload,
    received_at: $json.received_at,
  },
}];

return [{
  json: {
    ok: true,
    telegram_sent: false,
    alerts: $json.alerts,
    alert_count: $json.alert_count,
    payload: $json.payload,
    received_at: $json.received_at,
  },
}];
